    #region Concurrent Request Simulation - Simulating Parallel HTTP Requests

    private const int ConcurrentRequests = 16;

    [BenchmarkCategory("ConcurrentRequests"), Benchmark(Baseline = true)]
    public async Task<GetUserResponse[]> ConcurrentRequests_MSDI()
    {
        var tasks = new Task<GetUserResponse>[ConcurrentRequests];

        for(var i = 0; i < ConcurrentRequests; i++)
        {
            var userId = i + 1;
            tasks[i] = Task.Run(async () =>
            {
                using var scope = _msdiProvider.CreateScope();
                var handler = scope.ServiceProvider.GetRequiredService<IRequestHandler<GetUserRequest, GetUserResponse>>();

                return await handler.HandleAsync(new GetUserRequest(userId));
            });
        }

        return await Task.WhenAll(tasks);
    }

